  <text x="36" y="90" fill="#fafafa" font-size="14.5" font-weight="700" font-family="sans-serif">Mart 2020 · COVID Şoku</text>
  <text x="36" y="112" fill="#a1a1aa" font-size="13" font-family="sans-serif">Bitcoin'in kendi volatilite ölçüsü yıllık %200'ü aştı</text>
  <text x="664" y="100" fill="#22c55e" font-size="13.5" font-weight="700" text-anchor="end" font-family="sans-serif">Uç noktayı yakaladı</text>
  <rect x="20" y="142" width="660" height="70" rx="8" fill="#18181b"/>
  <text x="36" y="168" fill="#fafafa" font-size="14.5" font-weight="700" font-family="sans-serif">Kasım 2022 · FTX Çöküşü</text>
  <text x="36" y="190" fill="#a1a1aa" font-size="13" font-family="sans-serif">DVOL lansman sonrası zirvede, gerçek dip ise 21/11'de</text>
  <text x="664" y="178" fill="#fbbf24" font-size="13.5" font-weight="700" text-anchor="end" font-family="sans-serif">~10 günlük gecikme</text>
  <rect x="20" y="220" width="660" height="70" rx="8" fill="#18181b"/>
  <text x="36" y="246" fill="#fafafa" font-size="14.5" font-weight="700" font-family="sans-serif">2023 Başı · Rekor Düşük Volatilite</text>
  <text x="36" y="268" fill="#a1a1aa" font-size="13" font-family="sans-serif">Ardından gelen bir çöküş değil, ETF umut rallisiydi</text>
  <text x="664" y="256" fill="#60a5fa" font-size="13.5" font-weight="700" text-anchor="end" font-family="sans-serif">Yön sinyali yok</text>
  <rect x="20" y="298" width="660" height="70" rx="8" fill="#18181b"/>
  <text x="36" y="324" fill="#fafafa" font-size="14.5" font-weight="700" font-family="sans-serif">Ocak 2024 · Spot ETF Onayı</text>
  <text x="36" y="346" fill="#a1a1aa" font-size="13" font-family="sans-serif">Haftalar içinde %11+ düştü (klasik "haberi sat")</text>
  <text x="664" y="334" fill="#f7931a" font-size="13.5" font-weight="700" text-anchor="end" font-family="sans-serif">Olay primi eridi</text>
